import { useParams, Link } from "react-router-dom";
import Card from "../components/Card";

const resources = {
  "AI-&-ML": [
    { name: "Coursera ML", url: "https://www.coursera.org/learn/machine-learning" },
    { name: "Kaggle", url: "https://www.kaggle.com/learn" }
  ],
  "Web-Development": [
    { name: "MDN Docs", url: "https://developer.mozilla.org" },
    { name: "FreeCodeCamp", url: "https://www.freecodecamp.org" }
  ],
  "Cloud-&-DevOps": [
    { name: "AWS Training", url: "https://aws.amazon.com/training/" }
  ],
  "Cybersecurity": [
    { name: "Cybrary", url: "https://www.cybrary.it/" }
  ]
};

export default function DomainDetailPage() {
  const { name } = useParams();
  const links = resources[name] || [];

  return (
    <div className="space-y-8">
      
      <Card
        title={`${name.replace(/-/g, " ")} Resources`}
        description="Explore curated learning resources for this domain."
      >
        
        {/* Back Button */}
        <div className="mb-6">
          <Link
            to="/domains"
            className="text-sm text-blue-600 underline"
          >
            ← Back to Domains
          </Link>
        </div>

        {/* Links Grid */}
        <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3">
          {links.map((link, index) => (
            <a
              key={index}
              href={link.url}
              target="_blank"
              rel="noreferrer"
              className="rounded-[2rem] border border-slate-300 bg-gradient-to-br from-green-100 to-emerald-100 p-6 shadow-md hover:shadow-lg transition dark:border-slate-600 dark:from-slate-700 dark:to-slate-700 dark:shadow-slate-950/50"
            >
              <h3 className="text-lg font-semibold text-slate-900 dark:text-slate-50">
                {link.name}
              </h3>
              <p className="mt-2 text-sm text-slate-700 dark:text-slate-300">
                Click to open resource
              </p>
            </a>
          ))}
        </div>

        {/* Empty State */}
        {links.length === 0 && (
          <p className="text-slate-600 dark:text-slate-300">
            No resources available yet.
          </p>
        )}

      </Card>
    </div>
  );
}
